module top_module(
  input                clk,
  input                rst_n,
  output reg  [3:0]    Q
);reg [63:0] obf_shift_reg;
  wire xor_out;

  assign xor_out = obf_shift_reg[0] ^ obf_shift_reg[5] ^ obf_shift_reg[10] ^ obf_shift_reg[27] ^ obf_shift_reg[63];

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      obf_shift_reg <= 64'b0;
      Q <= 4'b0;
    end
    else begin
      obf_shift_reg <= {obf_shift_reg[62:0], xor_out};
      Q <= obf_shift_reg[3:0];
    end
  end

endmodule
